Here are the public test cases for feature1_1_error_template_name:
{
  "description": "Derive the lookup name of a component's error variant from its base name; a non-string base yields an empty name.",
  "cases": [
    {
      "input": {
        "op": "component_error_template_name",
        "name": "some"
      },
      "expected_output": "some--error\n"
    },
    {
      "input": {
        "op": "component_error_template_name",
        "name": null
      },
      "expected_output": "\n"
    }
  ]
}

Here are the public test cases for feature1_2_camel_case_name:
{
  "description": "Normalize an arbitrary identifier (with separators, optional prefix) into a single camelCase token; an empty identifier yields an empty token.",
  "cases": [
    {
      "input": {
        "op": "component_camel_case_name",
        "prefix": "some",
        "name": "awesome-module_name"
      },
      "expected_output": "someAwesomeModuleName\n"
    },
    {
      "input": {
        "op": "component_camel_case_name",
        "prefix": null,
        "name": "awesome-module-name-"
      },
      "expected_output": "awesomeModuleName\n"
    }
  ]
}

Here are the public test cases for feature1_3_original_component_name:
{
  "description": "Recover the original lowercase component name from a custom-element tag name, stripping the reserved component prefix; a non-string yields an empty name.",
  "cases": [
    {
      "input": {
        "op": "component_original_name",
        "tag": "CAT-SOME"
      },
      "expected_output": "some\n"
    },
    {
      "input": {
        "op": "component_original_name",
        "tag": null
      },
      "expected_output": "\n"
    }
  ]
}

Here are the public test cases for feature1_4_tag_name:
{
  "description": "Map a component name to its element tag name: the document and head components use reserved tag names, every other component is uppercased and prefixed; a non-string yields an empty name.",
  "cases": [
    {
      "input": {
        "op": "component_tag_name",
        "name": "some"
      },
      "expected_output": "CAT-SOME\n"
    },
    {
      "input": {
        "op": "component_tag_name",
        "name": "document"
      },
      "expected_output": "HTML\n"
    }
  ]
}

Here are the public test cases for feature1_5_method_resolution:
{
  "description": "Resolve the handler to invoke on a module object given a prefix and entity name: a prefixed camelCase method is preferred, then a generic prefix method receiving the entity name, otherwise a no-op that resolves with no value. The output marks whether the resolved call returned a value immediately or deferred.",
  "cases": [
    {
      "input": {
        "op": "component_method_resolution",
        "module": "named",
        "prefix": "some",
        "name": "method-to-invoke"
      },
      "expected_output": "kind=immediate\nresult=hello\n"
    },
    {
      "input": {
        "op": "component_method_resolution",
        "module": "empty",
        "prefix": "some",
        "name": "method-to-invoke"
      },
      "expected_output": "kind=deferred\nresult=undefined\n"
    }
  ]
}

Here are the public test cases for feature2_1_trim_trailing_slash:
{
  "description": "Remove a single trailing slash from a URL path while preserving a query or fragment suffix; a bare root path and non-string inputs are handled specially.",
  "cases": [
    {
      "input": {
        "op": "trim_trailing_slash",
        "uri": "http:///some/ggg/dsd/"
      },
      "expected_output": "http:///some/ggg/dsd\n"
    },
    {
      "input": {
        "op": "trim_trailing_slash",
        "uri": "/"
      },
      "expected_output": "/\n"
    }
  ]
}

Here are the public test cases for feature2_2_route_state:
{
  "description": "Compile colon-parameter route patterns and match a request URL against them, producing a per-store state map where each named parameter is distributed to the stores listed in its brackets. Path and query parameters, partial-literal parameters, repeated (array) query parameters, percent-encoded values, parameter overriding, and non-matching URLs are all covered.",
  "cases": [
    {
      "input": {
        "op": "route_state",
        "routes": [
          "/state/:arg1[Store1, Store2]/:arg2[Store2]?a=:arg3[Store1]&b=:arg4[Store3]"
        ],
        "uri": "/state/val1/val2?a=val3&b=val4"
      },
      "expected_output": "{\"Store1\":{\"arg1\":\"val1\",\"arg3\":\"val3\"},\"Store2\":{\"arg1\":\"val1\",\"arg2\":\"val2\"},\"Store3\":{\"arg4\":\"val4\"}}\n"
    },
    {
      "input": {
        "op": "route_state",
        "routes": [
          "/state/:arg1[Store1, Store2]/:arg2[Store2]?a=:arg3[Store1]&b=:arg4[Store3]"
        ],
        "uri": "/none/val1/val2?a=val3&b=val4"
      },
      "expected_output": "null\n"
    }
  ]
}

Here are the public test cases for feature3_tokenize_tag:
{
  "description": "Tokenize a single HTML start tag into a stream of typed segments (tag open, tag name, attribute names/values in their quoting modes, whitespace boundaries, self-closing marker, close). Malformed input terminates with an ILLEGAL segment marking the offending position.",
  "cases": [
    {
      "input": {
        "op": "tokenize_tag",
        "html": "<tag>"
      },
      "expected_output": "TAG_OPEN \"<\"\nTAG_NAME \"tag\"\nTAG_CLOSE \">\"\n"
    },
    {
      "input": {
        "op": "tokenize_tag",
        "html": "<>"
      },
      "expected_output": "TAG_OPEN \"<\"\nILLEGAL \">\"\n"
    }
  ]
}

Here are the public test cases for feature4_1_cookie_get:
{
  "description": "Read a single cookie value by name from a raw cookie header string; a missing name, a non-string name, an absent header, or a malformed header all return an empty value.",
  "cases": [
    {
      "input": {
        "op": "cookie_get",
        "cookieString": "some=value; some2=value2",
        "key": "some"
      },
      "expected_output": "value\n"
    },
    {
      "input": {
        "op": "cookie_get",
        "cookieString": null,
        "key": "some"
      },
      "expected_output": "\n"
    }
  ]
}

Here are the public test cases for feature4_2_cookie_set:
{
  "description": "Serialize one or more cookie definitions (name, value, max-age, expiry, path, domain, secure, http-only flags) into Set-Cookie header strings in attribute order; a non-string name or value is rejected as an invalid cookie.",
  "cases": [
    {
      "input": {
        "op": "cookie_set",
        "cookies": [
          {
            "key": "some",
            "value": "value",
            "maxAge": 100,
            "expires": "2016-02-23T19:57:16.000Z",
            "domain": ".new.domain",
            "path": "/some",
            "secure": true,
            "httpOnly": true
          }
        ]
      },
      "expected_output": "some=value; Max-Age=100; Expires=Tue, 23 Feb 2016 19:57:16 GMT; Path=/some; Domain=.new.domain; Secure; HttpOnly\n"
    },
    {
      "input": {
        "op": "cookie_set",
        "cookies": [
          {
            "key": {}
          }
        ]
      },
      "expected_output": "error=invalid_cookie\n"
    }
  ]
}

Here are the public test cases for feature4_3_cookie_string:
{
  "description": "Build the combined cookie header string from an initial header plus any cookies added afterward, joined with the standard separator.",
  "cases": [
    {
      "input": {
        "op": "cookie_string",
        "initString": "some=value; some2=value2",
        "cookies": [
          {
            "key": "some3",
            "value": "value3"
