          {
            "key": "some4",
            "value": "value4"
          }
        ]
      },
      "expected_output": "some=value; some2=value2; some3=value3; some4=value4\n"
    }
  ]
}

Here are the public test cases for feature4_4_cookie_all:
{
  "description": "Parse the combined cookie header into a name-to-value map.",
  "cases": [
    {
      "input": {
        "op": "cookie_all",
        "initString": "some=value; some2=value2",
        "cookies": []
      },
      "expected_output": "{\"some\":\"value\",\"some2\":\"value2\"}\n"
    }
  ]
}

