Here are the public test cases for feature5_6_inline_script:
{
  "description": "Produce the inline browser script that replays deferred server-side actions: assigning a redirect location, writing queued cookies, and clearing the URL fragment. Script-tag sequences inside values are neutralized.",
  "cases": [
    {
      "input": {
        "op": "inline_script",
        "ops": [
          {
            "action": "redirect",
            "uri": "http://some"
          }
        ]
      },
      "expected_output": "<script>window.location.assign('http://some');</script>\n"
    },
    {
      "input": {
        "op": "inline_script",
        "ops": [
          {
            "action": "set_cookie",
            "cookie": {
              "key": "some1",
              "value": "value1"
            }
          },
          {
            "action": "set_cookie",
            "cookie": {
              "key": "some2",
              "value": "value2"
            }
          }
        ]
      },
      "expected_output": "<script>window.document.cookie = 'some1=value1';window.document.cookie = 'some2=value2';</script>\n"
    }
  ]
}

Here are the public test cases for feature6_callback_to_promise:
{
  "description": "Adapt a Node-style callback function (final argument receives error-or-result) into a function returning a promise: a successful callback resolves with the result, an error callback rejects with the error message.",
  "cases": [
    {
      "input": {
        "op": "callback_to_promise",
        "callback": {
          "result": "hello"
        }
      },
      "expected_output": "resolved=hello\n"
    },
    {
      "input": {
        "op": "callback_to_promise",
        "callback": {
          "error": "hello"
        }
      },
      "expected_output": "rejected=hello\n"
    }
  ]
}
